#include <vector>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    // Initialize a 2D array to store the minimum cost to reach each cell
    vector<vector<long long>> dp(m, vector<long long>(n, LONG_MAX));

    // Starting cell (0, 0)
    dp[0][0] = (0 + 1) * (0 + 1); // Entry cost

    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    // Use a priority queue to perform Dijkstra's algorithm
    priority_queue<pair<long long, pair<int, int>>, vector<pair<long long, pair<int, int>>>, greater<>> pq;
    pq.push({dp[0][0], {0, 0}});

    while (!pq.empty()) {
        long long currentCost = pq.top().first;
        int x = pq.top().second.first;
        int y = pq.top().second.second;
        pq.pop();

        // If we have already found a better path to this cell, skip it
        if (currentCost > dp[x][y]) {
            continue;
        }

        // If we have reached the destination, return the cost
        if (x == m - 1 && y == n - 1) {
            return currentCost;
        }

        // Move to the next cell (right or down)
        for (auto& dir : directions) {
            int nx = x + dir.first;
            int ny = y + dir.second;

            // Check if the new cell is within bounds
            if (nx >= 0 && nx < m && ny >= 0 && ny < n) {
                long long newCost = currentCost + (nx + 1) * (ny + 1);
                if (newCost < dp[nx][ny]) {
                    dp[nx][ny] = newCost;
                    pq.push({newCost, {nx, ny}});
                }
            }
        }

        // Wait in the current cell (even second)
        if ((x + y + 1) % 2 == 0) { // Even second (since starting from 1st second)
            long long waitCostValue = waitCost[x][y];
            long long newCost = currentCost + waitCostValue;
            if (newCost < dp[x][y]) {
                dp[x][y] = newCost;
                pq.push({newCost, {x, y}});
            }
        }
    }

    // If we cannot reach the destination (should not happen in valid inputs)
    return -1;
}

